definition.script:
pipeline {
    agent { label 'windows' }
    triggers {
        pollSCM('H/5 * * * *')
    }
    environment {
        APP_NAME = 'arcana-windows'
        VERSION  = '0.1.0'
    }
    options {
        timeout(time: 30, unit: 'MINUTES')
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }
    stages {
        stage('Checkout') {
            steps {
                withCredentials([usernamePassword(credentialsId: 'github-credentials', usernameVariable: 'GIT_USER', passwordVariable: 'GIT_PASS')]) {
                    bat "if exist .git (git fetch --tags --force --progress https://%GIT_USER%:%GIT_PASS%@github.com/jrjohn/arcana-windows.git +refs/heads/*:refs/remotes/origin/* && git checkout -f origin/main) else (git clone --branch main https://%GIT_USER%:%GIT_PASS%@github.com/jrjohn/arcana-windows.git .)"
                }
            }
        }
        stage('Restore') {
            steps {
                bat "dotnet restore Arcana.Windows.sln --force-evaluate"
            }
        }
        stage('Build') {
            steps {
                bat "dotnet build src\\Arcana.App\\Arcana.App.csproj -c Release -p:Platform=x64 -maxcpucount:1"
            }
        }
        stage('Unit Tests') {
            steps {
                bat "if exist TestResults rmdir /s /q TestResults"
                bat "dotnet test -c Release -p:Platform=x64 --logger trx --results-directory TestResults || exit 0"
            }
            post {
                always {
                    junit allowEmptyResults: true, testResults: 'TestResults/**/*.trx'
                }
            }
        }
        stage('SonarQube Analysis') {
            steps {
                echo "Windows remote agent requires dotnet-sonarscanner + Java -- skipping (see advanced setup)"
            }
        }
        stage('Publish EXE') {
            steps {
                bat "if exist artifacts\\exe rmdir /s /q artifacts\\exe"
                bat "dotnet publish src\\Arcana.App\\Arcana.App.csproj -c Release -p:Platform=x64 -p:WindowsPackageType=None --self-contained -r win-x64 -o artifacts\\exe -maxcpucount:1"
                archiveArtifacts artifacts: 'artifacts/exe/Arcana.App.exe', fingerprint: true
            }
        }
        stage('MSIX Package') {
            steps {
                bat "if exist artifacts\\msix rmdir /s /q artifacts\\msix"
                bat "dotnet publish src\\Arcana.App\\Arcana.App.csproj -c Release -p:Platform=x64 -p:WindowsPackageType=MSIX -p:AppxPackageSigningEnabled=false -p:GenerateAppxPackageOnBuild=true -maxcpucount:1"
                bat "mkdir artifacts\\msix 2>NUL & copy /Y src\\Arcana.App\\obj\\x64\\Release\\net10.0-windows10.0.19041.0\\win-x64\\MsixContent\\MSIX\\*.msix artifacts\\msix\\ 2>NUL & echo MSIX collected"
                archiveArtifacts artifacts: 'artifacts/msix/*.msix', fingerprint: true, allowEmptyArchive: true
            }
        }
    }
    post {
        success { echo "Windows build SUCCESS - ${APP_NAME} v${VERSION} (EXE + MSIX)" }
        failure { echo "Windows build FAILED - ${APP_NAME}" }
        always  { echo "Build number ${BUILD_NUMBER} done" }
    }
}
